import os
import re
import json
import csv
from collections import defaultdict, deque

def parse_store_orders():
    orders = defaultdict(lambda: defaultdict(lambda: defaultdict(int)))
    dir_path = "/app/raw_orders/"
    for fname in os.listdir(dir_path):
        m = re.match(r"day_(\d+)_S_(\d+)_", fname)
        if not m: continue
        day = int(m.group(1))
        store = f"S_{m.group(2)}"
        path = os.path.join(dir_path, fname)
        with open(path) as f:
            if "text-template" in fname:
                for line in f:
                    m2 = re.search(r"deliver (\d+) units of product (P_\d+)", line)
                    if m2: orders[day][store][m2.group(2)] += int(m2.group(1))
            elif "key-value" in fname:
                for line in f:
                    m2 = re.search(r"ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)", line)
                    if m2: orders[day][store][m2.group(1)] += int(m2.group(2))
            elif "table-csv" in fname:
                reader = csv.reader(f, delimiter=';')
                next(reader)
                for row in reader:
                    if len(row) == 2: orders[day][store][row[0]] += int(row[1])
            elif "api-json" in fname:
                data = json.load(f)
                for item in data.get("items", []):
                    orders[day][store][item["prod_id"]] += int(item["qty"])
    return orders

def parse_supplier_receipts():
    # returns dict: day -> supplier -> product -> qty
    receipts = defaultdict(lambda: defaultdict(lambda: defaultdict(int)))
    dir_path = "/app/raw_supplier_receipts/"
    for fname in os.listdir(dir_path):
        m = re.match(r"day_(\d+)_PR_(\d+)_", fname)
        if not m: continue
        day = int(m.group(1))
        supplier = f"PR_{m.group(2)}"
        path = os.path.join(dir_path, fname)
        with open(path) as f:
            if "text-template" in fname:
                for line in f:
                    # Supplier PR_10 delivered 12 units of product P_1 to the wholesaler
                    m2 = re.search(r"delivered (\d+) units of product (P_\d+)", line)
                    if m2: receipts[day][supplier][m2.group(2)] += int(m2.group(1))
            elif "key-value" in fname:
                for line in f:
                    # PRODUCT: P_1 | DELIVERED_QTY: 14
                    m2 = re.search(r"PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)", line)
                    if m2: receipts[day][supplier][m2.group(1)] += int(m2.group(2))
            elif "table-csv" in fname:
                reader = csv.reader(f, delimiter=';')
                next(reader)
                for row in reader:
                    if len(row) == 2: receipts[day][supplier][row[0]] += int(row[1])
            elif "api-json" in fname:
                data = json.load(f)
                for item in data.get("items", []):
                    receipts[day][supplier][item["prod_id"]] += int(item["delivered_qty"])
    return receipts

def parse_wholesaler_receipts():
    # returns dict: day -> seq -> supplier
    # actually better: day -> list of suppliers ordered by seq
    receipts = defaultdict(dict)
    dir_path = "/app/raw_wholesaler_receipts/"
    for fname in os.listdir(dir_path):
        m = re.match(r"day_(\d+)_PR_(\d+)_receipt\.txt", fname)
        if not m: continue
        day = int(m.group(1))
        supplier = f"PR_{m.group(2)}"
        path = os.path.join(dir_path, fname)
        with open(path) as f:
            content = f.read()
            m2 = re.search(r"DAILY_SEQUENCE_NO:\s*(\d+)", content)
            if m2:
                seq = int(m2.group(1))
                receipts[day][seq] = supplier

    ordered = {}
    for day, seq_dict in receipts.items():
        ordered[day] = [seq_dict[seq] for seq in sorted(seq_dict.keys())]
    return ordered

def parse_wholesaler_store_receipts():
    # dict: day -> seq -> (store, total_units)
    receipts = defaultdict(dict)
    dir_path = "/app/raw_wholesaler_store_receipts/"
    for fname in os.listdir(dir_path):
        m = re.match(r"day_(\d+)_S_(\d+)_receipt\.txt", fname)
        if not m: continue
        day = int(m.group(1))
        store = f"S_{m.group(2)}"
        path = os.path.join(dir_path, fname)
        with open(path) as f:
            content = f.read()
            seq_m = re.search(r"DAILY_SEQUENCE_NO:\s*(\d+)", content)
            tot_m = re.search(r"TOTAL_DELIVERED_UNITS:\s*(\d+)", content)
            if seq_m and tot_m:
                seq = int(seq_m.group(1))
                tot = int(tot_m.group(1))
                receipts[day][seq] = (store, tot)

    ordered = {}
    for day, seq_dict in receipts.items():
        ordered[day] = [seq_dict[seq] for seq in sorted(seq_dict.keys())]
    return ordered

print("Parsing...")
store_orders = parse_store_orders()
supplier_receipts = parse_supplier_receipts()
ws_receipts = parse_wholesaler_receipts()
ws_store_receipts = parse_wholesaler_store_receipts()
print("Done parsing.")
