import pandas as pd
import numpy as np
from simulate import store_orders, supplier_receipts, ws_receipts, ws_store_receipts
from collections import defaultdict, deque
import json

df = pd.read_csv('/app/sales_log.csv')
sales_dict = df.groupby(['Day', 'Store_ID', 'Product_ID'])['Sold_Quantity'].sum().to_dict()
demand_dict = df.groupby(['Day', 'Store_ID', 'Product_ID'])['Reported_Demand'].sum().to_dict()

wholesaler_inventory = defaultdict(deque)
store_inventory = defaultdict(lambda: defaultdict(deque))
# Track sales: day -> store -> product -> dict of producer -> qty sold
sales_trace = defaultdict(lambda: defaultdict(lambda: defaultdict(lambda: defaultdict(int))))

for day in range(1, 366):
    if day in ws_receipts:
        for producer in ws_receipts[day]:
            if day in supplier_receipts and producer in supplier_receipts[day]:
                for product in sorted(supplier_receipts[day][producer].keys()):
                    qty = supplier_receipts[day][producer][product]
                    wholesaler_inventory[product].append([producer, qty])

    if day in ws_store_receipts:
        for store, expected_total in ws_store_receipts[day]:
            if day in store_orders and store in store_orders[day]:
                for product in sorted(store_orders[day][store].keys()):
                    qty_to_fulfill = store_orders[day][store][product]
                    while qty_to_fulfill > 0 and wholesaler_inventory[product]:
                        batch = wholesaler_inventory[product][0]
                        take = min(qty_to_fulfill, batch[1])
                        batch[1] -= take
                        qty_to_fulfill -= take
                        if store_inventory[store][product] and store_inventory[store][product][-1][0] == batch[0]:
                            store_inventory[store][product][-1][1] += take
                        else:
                            store_inventory[store][product].append([batch[0], take])
                        if batch[1] == 0:
                            wholesaler_inventory[product].popleft()

    # Store sells
    for store in [f"S_{i}" for i in range(1, 11)]:
        for product in [f"P_{i}" for i in range(1, 31)]:
            sold = sales_dict.get((day, store, product), 0)
            qty_to_sell = sold
            while qty_to_sell > 0 and store_inventory[store][product]:
                batch = store_inventory[store][product][0]
                take = min(qty_to_sell, batch[1])
                batch[1] -= take
                qty_to_sell -= take
                sales_trace[day][store][product][batch[0]] += take
                if batch[1] == 0:
                    store_inventory[store][product].popleft()

print("Trace complete.")

# Now detect rejections
# A rejection on day D for product P at store S causes demand drops on days D+1 to D+14.
